}

.bean-left {
  display: flex;
  align-items: center;
  gap: 6px;
}

.bean-label { font-size: 12px; color: #6B2D03; }

.bean-svg { flex-shrink: 0; }

.bean-amount {
  font-size: 18px; font-weight: 600;
  color: #FF9045;
  font-family: "Baloo 2", "Baloo", sans-serif;
}

.bean-arrow { color: #FF9045; font-size: 14px; }

.help-btn {
  width: 24px; height: 24px;
  border: 1px solid #ECCEAF;
  border-radius: 50%;
