/* ===== 金刚区 ===== */
.kingkong-zone {
  margin: 0;
  position: relative;
  height: 67px;
}

.kingkong-scroll {
  display: flex;
  gap: 0;
  overflow-x: auto;
  padding: 0 20px;
  height: 55px;
  align-items: flex-end;
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.kingkong-scroll::-webkit-scrollbar { display: none; }

.kingkong-item {
  flex-shrink: 0;
  width: 64px;
  height: 55px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  position: relative;
}

.kingkong-icon {
  width: 40px; height: 40px;
  border-radius: 12px;
  background: #f0f0f0;
}

.kingkong-item > span:first-of-type {
  font-size: 11px; color: #666;
  white-space: nowrap;
}

.kingkong-item span {
  font-size: 11px; color: #666;
  white-space: nowrap;
}

/* 上新气泡 - Figma 气泡样式（带小尖尖） */
.badge-new {
  position: absolute;
  top: -2px;
  right: 2px;
  background: none;
  font-size: 10px; color: #544300;
  padding: 0;
  border-radius: 0;
  line-height: 1.4;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.badge-new::before {
  content: '上新';
  background: #FCDA00;
  padding: 2px 5px;
  border-radius: 80px;
  font-size: 10px;
  color: #544300;
  line-height: 1.4;
  white-space: nowrap;
}
.badge-new::after {
  content: '';
  display: block;
  width: 0;
  height: 0;
  border-left: 4px solid transparent;
  border-right: 4px solid transparent;
  border-top: 3px solid #FCDA00;
  margin-top: 0px;
  margin-right: 2px;
  align-self: flex-end;
}

.kingkong-indicator {
  display: flex;
  justify-content: center;
  gap: 0;
  position: absolute;
  bottom: 4px;
  left: 0;
  right: 0;
}

.indicator-track {
  width: 32px; height: 4px;
  background: #D9D9D9;
  border-radius: 2px;
  position: relative;
  overflow: hidden;
}

.indicator-active {
  position: absolute;
  left: 0;
  width: 20px; height: 4px;
  background: #FCDA00;
  border-radius: 2px;
}

