  line-height: 21px;
}

.rec-body {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.rec-icon {
  width: 44px; height: 44px;
  border-radius: 8px;
  background: #ffe0c0;
}

.rec-tag {
  font-size: 12px; color: #FF9045;
  white-space: nowrap;
}

.rec-price {
  font-size: 12px; font-weight: 600;
  color: #FF9045;
  font-family: "Baloo 2", "Baloo", sans-serif;
}

/* ===== 分类筛选 ===== */
.filter-section {
  position: sticky;
  top: 88px;
  z-index: 99;
  background: white;
  border-top: 0.6px solid #E0DFDF;
  height: auto;
  overflow: hidden;
}

.category-tabs {
  display: flex;
  gap: 24px;
  padding: 10px 20px 0;
  overflow-x: auto;
  -ms-overflow-style: none;
