}
.cat-tab.active {
  color: #404040;
  font-weight: 500;
  border-bottom: 2px solid #FCDA00;
}

.price-filters {
  display: flex;
  gap: 8px;
  padding: 6px 20px 6px;
  overflow-x: auto;
  -ms-overflow-style: none;
  scrollbar-width: none;
  box-shadow: 0px 2px 8px rgba(0, 0, 0, 0.08);
}
.price-filters::-webkit-scrollbar { display: none; }

