  white-space: nowrap;
}
.price-chip.active {
  background: #FCDA00;
  color: #544300;
  border-color: #FCDA00;
}

.search-btn {
  position: absolute;
  right: 10px; top: 0px;
  border: none; background: transparent;
  border-left: 1px solid rgba(0,0,0,0.08);
  padding: 4px 10px;
  cursor: pointer;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* ===== 上滑滚动区域 ===== */
.scroll-area {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  min-height: 0;
  -webkit-overflow-scrolling: touch;
}

