}

/* ===== 商品列表 ===== */
.product-list {
  padding: 0 20px 20px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.product-row {
  display: flex;
  gap: 6px;
}

/* --- 商品卡片 --- */
.product-card {
  flex: 1;
  background: white;
  border-radius: 10px;
  overflow: hidden;
  position: relative;
}

.product-card-empty {
  background: transparent;
  border-radius: 0;
