  display: flex;
  align-items: center;
  gap: 4px;
}

.bean-svg-sm {
  flex-shrink: 0;
}

.product-price {
  font-size: 18px; font-weight: 600;
  color: #FF9045;
  font-family: "Baloo 2", "Baloo", sans-serif;
}

.product-old-price {
  font-size: 12px; color: #B2B2B2;
  text-decoration: line-through;
}

.product-sold {
  font-size: 12px; color: #B2B2B2;
  margin-left: auto;
}

/* --- 标签 --- */
