  position: absolute;
  top: 0; right: 8px;
  background: #FF8031;
  color: white;
  font-size: 12px;
  padding: 4px 8px;
  border-radius: 2px;
  border: 2px solid white;
  z-index: 10;
}

/* ===== 活动卡片 ===== */
.promo-card {
  flex: 1;
  background: #FFF4ED;
  border-radius: 10px;
  padding: 14px;
  min-height: 238px;
  display: flex;
  flex-direction: column;
}

.promo-tag {
  font-size: 10px; color: #A66A29;
  background: white;
  border: 1px solid #CDA285;
  border-radius: 20px;
  padding: 2px 8px;
  display: inline-block;
  width: fit-content;
  margin-bottom: 8px;
}

.promo-title {
  font-size: 28px; font-weight: 800;
  color: #FE9627;
  line-height: 1.2;
}

.promo-subtitle {
  font-size: 20px; font-weight: 800;
  color: #99491B;
  line-height: 1.2;
  margin-bottom: 8px;
}

.promo-btn {
  background: #FCDA00;
  border: none;
  border-radius: 25px;
  padding: 6px 26px;
  font-size: 16px; font-weight: 500;
  color: #6B430B;
  cursor: pointer;
  width: fit-content;
  margin-top: auto;
}

/* ===== 邀请好友横幅 ===== */
