  background: #FFEDED;
  border-radius: 16px;
  padding: 16px 20px;
  text-align: center;
  position: relative;
  overflow: hidden;
}

.invite-highlight {
  color: #FE9627;
  font-size: 18px; font-weight: 800;
}

.invite-dark {
  color: #99491B;
  font-size: 18px; font-weight: 800;
}

.invite-sub {
  font-size: 12px; color: #A66A29;
  background: white;
  border: 1px solid #CDA285;
  border-radius: 999px;
  padding: 2px 11px;
  display: inline-block;
  margin-top: 4px;
  letter-spacing: 2px;
}

/* ===== 购物车 ===== */
