  position: fixed;
  bottom: 40px;
  left: 50%;
  transform: translateX(-50%);
  margin-left: -140px;
  z-index: 200;
}

.cart-icon {
  width: 50px; height: 50px;
  background: white;
  border-radius: 50%;
  box-shadow: 0 2px 6px rgba(0,0,0,0.08), 0 4px 8px rgba(0,0,0,0.12);
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  border: 2px solid white;
}

