/* 全局样式 */
* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  height: 100vh;
  display: flex;
  justify-content: center;
  background: #f5f5f5;
  font-family: "PingFang SC", -apple-system, BlinkMacSystemFont, "Helvetica Neue", sans-serif;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

.page {
  background: white;
  width: 375px;
  height: 100vh;
  position: relative;
  overflow-y: auto;
  overflow-x: hidden;
  padding-bottom: 64px;
  -webkit-overflow-scrolling: touch;
}

/* ===== 导航栏 ===== */
.navbar {
  position: sticky;
  top: 0;
  z-index: 100;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  background: rgba(255,255,255,0.9);
}

.status-bar {
  height: 44px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0 20px;
}
.time { font-size: 14px; font-weight: 600; }
.status-svg { fill: black; }

.nav-bar {
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.nav-back {
  position: absolute;
  left: 0; top: 0;
  width: 44px; height: 44px;
  border: none; background: none;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; padding: 0;
}

.nav-title {
  font-size: 18px; font-weight: 500;
  color: black;
}

.nav-more {
  position: absolute;
  right: 0; top: 0;
  width: 44px; height: 44px;
  border: none; background: none;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; padding: 0;
}

/* ===== 学豆余额 ===== */
.bean-balance {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 20px;
  background: rgba(255,183,106,0.15);
  margin: 0 20px;
  border-radius: 16px;
}

.bean-left {
  display: flex;
  align-items: center;
  gap: 6px;
}

.bean-label { font-size: 12px; color: #6B2D03; }

.bean-svg { flex-shrink: 0; }

.bean-amount {
  font-size: 18px; font-weight: 600;
  color: #FF9045;
  font-family: "Baloo 2", "Baloo", sans-serif;
}

.bean-arrow { color: #FF9045; font-size: 14px; }

.help-btn {
  width: 24px; height: 24px;
  border: 1px solid #ECCEAF;
  border-radius: 50%;
  background: none;
  color: #ECCEAF;
  font-size: 14px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
}

/* ===== 金刚区 ===== */
.kingkong-zone {
  margin: 0;
  position: relative;
  height: 67px;
}

.kingkong-scroll {
  display: flex;
  gap: 0;
  overflow-x: auto;
  padding: 0 20px;
  height: 55px;
  align-items: flex-end;
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.kingkong-scroll::-webkit-scrollbar { display: none; }

.kingkong-item {
  flex-shrink: 0;
  width: 64px;
  height: 55px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  position: relative;
}

.kingkong-icon {
  width: 40px; height: 40px;
  border-radius: 12px;
  background: #f0f0f0;
}

.kingkong-item > span:first-of-type {
  font-size: 11px; color: #666;
  white-space: nowrap;
}

.kingkong-item span {
  font-size: 11px; color: #666;
  white-space: nowrap;
}

/* 上新气泡 - Figma 气泡样式（带小尖尖） */
.badge-new {
  position: absolute;
  top: -2px;
  right: 2px;
  background: none;
  font-size: 10px; color: #544300;
  padding: 0;
  border-radius: 0;
  line-height: 1.4;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.badge-new::before {
  content: '上新';
  background: #FCDA00;
  padding: 2px 5px;
  border-radius: 80px;
  font-size: 10px;
  color: #544300;
  line-height: 1.4;
  white-space: nowrap;
}
.badge-new::after {
  content: '';
  display: block;
  width: 0;
  height: 0;
  border-left: 4px solid transparent;
  border-right: 4px solid transparent;
  border-top: 3px solid #FCDA00;
  margin-top: 0px;
  margin-right: 2px;
  align-self: flex-end;
}

.kingkong-indicator {
  display: flex;
  justify-content: center;
  gap: 0;
  position: absolute;
  bottom: 4px;
  left: 0;
  right: 0;
}

.indicator-track {
  width: 32px; height: 4px;
  background: #D9D9D9;
  border-radius: 2px;
  position: relative;
  overflow: hidden;
}

.indicator-active {
  position: absolute;
  left: 0;
  width: 20px; height: 4px;
  background: #FCDA00;
  border-radius: 2px;
}

/* ===== 学豆余额区域下方间距 ===== */
.bean-balance + .kingkong-zone {
  margin-top: 8px;
}

